import 'package:injectable/injectable.dart'; import '../model/input_event.dart'; @injectable class InputTranslator { InputEvent translateToRemote(InputEvent event, double scaleX, double scaleY) { if (event.x == null) return event; return InputEvent(type: event.type, x: event.x! * scaleX, y: event.y! * scaleY, endX: event.endX != null ? event.endX! * scaleX : null, endY: event.endY != null ? event.endY! * scaleY : null, text: event.text, keyCode: event.keyCode, timestamp: event.timestamp); } }